const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const { Client, LocalAuth, MessageMedia } = require('whatsapp-web.js'); 
const multer = require('multer');
const xlsx = require('xlsx');
const cors = require('cors');
const fs = require('fs');
const path = require('path');
const admin = require('firebase-admin');

require('dotenv').config({ path: path.join(__dirname, '.env') });

const app = express();

const serviceAccountPath = path.join(__dirname, 'firebase-service-account.json');
if (fs.existsSync(serviceAccountPath)) {
    admin.initializeApp({
        credential: admin.credential.cert(require(serviceAccountPath))
    });
    console.log('[Firebase Admin] Connected.');
} else {
    console.error('❌ CRITICAL: firebase-service-account.json missing!');
}

app.use(cors({ 
    origin: ['http://localhost:5173', 'http://127.0.0.1:5173', 'http://localhost:4173'],
    credentials: true 
}));
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const server = http.createServer(app);
const io = new Server(server, { 
    cors: { 
        origin: ['http://localhost:5173', 'http://127.0.0.1:5173', 'http://localhost:4173'],
        methods: ["GET", "POST"],
        credentials: true
    } 
});

const multerStorage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'uploads/'),
    filename: (req, file, cb) => {
        const unique = Date.now() + '_' + Math.round(Math.random() * 1e9);
        const ext = path.extname(file.originalname) || '.jpg';
        cb(null, unique + ext);
    }
});
// FIXED INTERCEPTOR: Express interceptor maps strictly to the explicit 'broadcastImage' multipart form element
const upload = multer({ storage: multerStorage });

if (!fs.existsSync('uploads')) fs.mkdirSync('uploads');

const activeInstances = {};
const lastGeneratedQRs = {}; 
const sessionProfiles = [
    { id: "terminal_alpha", name: "Sales Department Line", status: "Offline", phone: "" },
    { id: "terminal_beta", name: "Customer Support Desk", status: "Offline", phone: "" },
    { id: "terminal_gamma", name: "Marketing Blast SIM", status: "Offline", phone: "" }
];

const campaignScheduleQueue = [];

async function authenticateUserToken(req, res, next) {
    const headerPayload = req.headers.authorization;
    if (!headerPayload || !headerPayload.startsWith('Bearer ')) {
        return res.status(401).json({ error: "Access Denied." });
    }
    const token = headerPayload.split(' ')[1];
    try {
        req.user = await admin.auth().verifyIdToken(token); 
        next();
    } catch (err) {
        return res.status(403).json({ error: "Access Expired." });
    }
}

function startWhatsAppInstance(instanceId) {
    if (activeInstances[instanceId]) return;
    const targetProfile = sessionProfiles.find(p => p.id === instanceId);
    if (targetProfile) targetProfile.status = "Initializing";

    const client = new Client({
        authStrategy: new LocalAuth({ clientId: instanceId }),
        puppeteer: {
            headless: true,
            args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage', '--disable-extensions']
        }
    });

    client.on('qr', (qrText) => {
        lastGeneratedQRs[instanceId] = qrText; 
        if (targetProfile) targetProfile.status = "Awaiting Scan";
        io.emit('profiles_update', sessionProfiles); 
        io.to(instanceId).emit('qr_code', { qr: qrText, instanceId });
    });

    client.on('ready', () => {
        delete lastGeneratedQRs[instanceId]; 
        if (targetProfile) {
            targetProfile.status = "Connected";
            targetProfile.phone = client.info.wid.user;
        }
        io.emit('profiles_update', sessionProfiles);
        io.to(instanceId).emit('status_change', { status: 'Connected', instanceId, phone: client.info.wid.user });
    });

    client.on('disconnected', async () => {
        if (targetProfile) {
            targetProfile.status = "Offline";
            targetProfile.phone = "";
        }
        io.emit('profiles_update', sessionProfiles);
        io.to(instanceId).emit('status_change', { status: 'Disconnected', instanceId });
        try { await client.destroy(); } catch (e) {}
        delete activeInstances[instanceId];
        delete lastGeneratedQRs[instanceId];
    });

    activeInstances[instanceId] = client;
    client.initialize().catch(() => {
        if (targetProfile) targetProfile.status = "Offline";
        io.emit('profiles_update', sessionProfiles);
        delete activeInstances[instanceId];
    });
}

io.on('connection', (socket) => {
    socket.emit('profiles_update', sessionProfiles);
    socket.on('join_instance', ({ instanceId }) => {
        socket.join(instanceId);
        if (activeInstances[instanceId]?.info) {
            socket.emit('status_change', { status: 'Connected', instanceId, phone: activeInstances[instanceId].info.wid.user });
        } else {
            if (lastGeneratedQRs[instanceId]) socket.emit('qr_code', { qr: lastGeneratedQRs[instanceId], instanceId });
            startWhatsAppInstance(instanceId);
        }
    });
});

app.post('/api/upload-recipients', authenticateUserToken, upload.single('excelFile'), (req, res) => {
    if (!req.file) return res.status(400).json({ error: "No document uploaded." });
    try {
        const Workbook = xlsx.readFile(req.file.path);
        const targetedSheet = Workbook.SheetNames[0];
        const rawJsonRows = xlsx.utils.sheet_to_json(Workbook.Sheets[targetedSheet]);
        fs.unlinkSync(req.file.path);
        return res.json({ success: true, data: rawJsonRows });
    } catch (error) {
        if (fs.existsSync(req.file.path)) fs.unlinkSync(req.file.path);
        return res.status(500).json({ error: "Failed processing sheet." });
    }
});

function buildMessage(template, record) {
    let msg = template || '';
    Object.keys(record).forEach(key => {
        msg = msg.replace(new RegExp(`{{${key}}}`, 'g'), record[key]);
    });
    return msg;
}

async function sendOneMessage(client, targetId, text, imagePath, captionText) {
    if (imagePath && fs.existsSync(imagePath)) {
        const media = MessageMedia.fromFilePath(imagePath);
        await client.sendMessage(targetId, media, { caption: captionText || text });
        if (captionText && text && text.trim()) {
            await new Promise(r => setTimeout(r, 800));
            await client.sendMessage(targetId, text);
        }
    } else {
        await client.sendMessage(targetId, text);
    }
}

// FIXED: Bulletproof conditional checker intercepts lists gracefully to prevent 500 error crashes
app.post('/api/broadcast', authenticateUserToken, upload.single('broadcastImage'), async (req, res) => {
    let imagePath = req.file ? req.file.path : null;
    
    try {
        const { instanceId, messageTemplate, imageCaption } = req.body;

        let list = req.body.list;
        if (!list) {
            if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);
            return res.status(400).json({ success: false, error: "Missing active contact list." });
        }

        if (typeof list === 'string') {
            try { list = JSON.parse(list); } catch (e) {
                if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);
                return res.status(400).json({ success: false, error: "Invalid syntax layout format." });
            }
        }

        const client = activeInstances[instanceId];
        if (!client) {
            if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);
            return res.status(400).json({ success: false, error: "WhatsApp terminal profile offline or unlinked." });
        }

        res.json({ success: true, status: "Broadcast active." });

        for (const record of list) {
            let rawPhone = String(record.Phone || record.phone || '').replace(/[\s+.-]/g, '');
            if (!rawPhone) continue;

            try {
                const contactIdDetails = await client.getNumberId(rawPhone);
                if (!contactIdDetails) continue;

                const targetId = contactIdDetails._serialized;
                const personalisedText = buildMessage(messageTemplate, record);
                const personalisedCaption = imageCaption ? buildMessage(imageCaption, record) : '';

                await sendOneMessage(client, targetId, personalisedText, imagePath, personalisedCaption);
                await new Promise(resolve => setTimeout(resolve, 4500));
            } catch (failLog) {
                console.error(`[Error]`, failLog.message);
            }
        }

        if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);

    } catch (err) {
        if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);
        return res.status(500).json({ success: false, error: err.message });
    }
});

app.post('/api/schedule-broadcast', authenticateUserToken, upload.single('broadcastImage'), (req, res) => {
    let imagePath = req.file ? req.file.path : null;
    try {
        const { instanceId, messageTemplate, scheduledTimestamp, imageCaption } = req.body;

        let list = req.body.list;
        if (typeof list === 'string') list = JSON.parse(list);

        const taskJobElement = {
            id: "job_" + Date.now(),
            instanceId,
            list,
            messageTemplate,
            imageCaption: imageCaption || '',
            imagePath, 
            executeAt: new Date(scheduledTimestamp).getTime(),
            status: "Scheduled"
        };

        campaignScheduleQueue.push(taskJobElement);
        return res.json({ success: true, jobId: taskJobElement.id });
    } catch (err) {
        if (imagePath && fs.existsSync(imagePath)) fs.unlinkSync(imagePath);
        return res.status(500).json({ success: false, error: err.message });
    }
});

app.post('/api/generate-template', authenticateUserToken, async (req, res) => {
    const { businessContext, tone, sampleRow } = req.body;
    if (!businessContext) return res.status(400).json({ error: "Context string values required." });

    let activeKey = process.env.GEMINI_API_KEY ? process.env.GEMINI_API_KEY.trim() : 'AIzaSyAQ.Ab8RN6IuBCtddvHGJKv7Uap1unFl5IJVHbyr61M9F-ARChBALw';
    let variableHooks = ['Name', 'Company']; 
    if (sampleRow && typeof sampleRow === 'object') {
        Object.keys(sampleRow).forEach(key => {
            if (!['Phone', 'phone', 'Name', 'Company'].includes(key)) variableHooks.push(key);
        });
    }
    const ruleStringTags = variableHooks.map(hook => `{{${hook}}}`).join(', ');

    try {
        const systemInstruction = `You are an elite copywriting engine. Generate a single highly engaging WhatsApp campaign message based on the context: "${businessContext}". Embed tracking tokens string metrics: [${ruleStringTags}]. Return ONLY the message text template copy without notes. Tone style: ${tone}.`;
        const aiResponse = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${activeKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ contents: [{ parts: [{ text: systemInstruction }] }] })
        });
        const data = await aiResponse.json();
        if (data.error) return res.status(400).json({ error: data.error.message });
        return res.json({ success: true, text: data.candidates[0].content.parts[0].text.trim() });
    } catch (error) { return res.status(500).json({ error: error.message }); }
});

setInterval(async () => {
    const currentClockTick = Date.now();
    for (const task of campaignScheduleQueue) {
        if (task.status === "Scheduled" && currentClockTick >= task.executeAt) {
            task.status = "Executing";
            const liveClientNodeRef = activeInstances[task.instanceId];
            if (!liveClientNodeRef) {
                task.status = "Failed - Channel Instance Offline";
                if (task.imagePath && fs.existsSync(task.imagePath)) fs.unlinkSync(task.imagePath);
                continue;
            }
            runDelayedTaskBroadcast(liveClientNodeRef, task);
        }
    }
}, 5000);

async function runDelayedTaskBroadcast(client, job) {
    for (const item of job.list) {
        let phone = String(item.Phone || item.phone || '').replace(/[\s+.-]/g, '');
        if (!phone) continue;
        try {
            const checkId = await client.getNumberId(phone);
            if (!checkId) continue;
            await sendOneMessage(client, checkId._serialized, buildMessage(job.messageTemplate, item), job.imagePath, job.imageCaption ? buildMessage(job.imageCaption, item) : '');
            await new Promise(r => setTimeout(r, 4500));
        } catch (e) { console.error(e.message); }
    }
    if (job.imagePath && fs.existsSync(job.imagePath)) fs.unlinkSync(job.imagePath);
    job.status = "Completed Successfully";
}

server.listen(4000, () => console.log('Backend engine operating safely on port 4000'));